if (!callbackUrl || !orgId) return items;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': 't+KHcyHWsievwSbCyHvDJk5/YbZayMsiKp0letIw0Xk='
    },
    body: {
      org_id: orgId,
      status: 'searching',
      stage_message: 'Searching Grants.gov and federal databases...'
    }
  });
} catch(e) {
  // Don't fail the workflow if status update fails
}

return items;

// CA Grants Portal Scraper
// Paginates through search results for open grants, then scrapes each detail page
const grants = [];
const allGrantUrls = [];

// Step 1: Paginate through search results to collect all grant URLs
for (let page = 1; page <= 10; page++) {
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.grants.ca.gov/?s=&grant_status=open&paged=' + page,
      headers: { 'User-Agent': 'Mozilla/5.0' },
    });
    if (typeof html !== 'string') break;
    const links = html.match(/href="(https:\/\/www\.grants\.ca\.gov\/grants\/[^"]+)"/g) || [];
    const pageUrls = links.map(l => l.match(/href="([^"]+)"/)[1]).filter((v, i, a) => a.indexOf(v) === i);
    if (pageUrls.length === 0) break;
    allGrantUrls.push(...pageUrls);
  } catch(e) { break; }
}

// Deduplicate URLs
const uniqueUrls = [...new Set(allGrantUrls)];

// Step 2: Fetch each grant detail page and extract data
for (const url of uniqueUrls) {
  try {
    const html = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': 'Mozilla/5.0' },
    });
    if (typeof html !== 'string') continue;

    // Extract title
    const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i);
    const title = titleMatch ? titleMatch[1].trim() : '';
    if (!title) continue;

    // Extract grantor/agency
    const agencyMatch = html.match(/[Gg]rantor[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/[Aa]gency[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i);
    const agency = agencyMatch ? agencyMatch[1].replace(/&amp;/g, '&').trim() : 'California State';

    // Extract description from paragraphs
    const descMatch = html.match(/[Dd]escription[^<]*<\/(?:h[2-4]|dt|th|strong)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4]|<dt)/i);
    let description = '';
    if (descMatch) {
      description = descMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 1000);
    }
    if (!description) {
      const paragraphs = html.match(/<p[^>]*>([\s\S]*?)<\/p>/gi) || [];
      description = paragraphs.slice(0, 3).map(p => p.replace(/<[^>]+>/g, '').trim()).filter(p => p.length > 30).join(' ').substring(0, 1000);
    }

    // Extract deadline
    let deadline = 'See listing';
    const deadlineMatch = html.match(/[Dd]eadline[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/[Cc]lose[^<]*[Dd]ate[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i)
      || html.match(/([\d]{1,2}\/[\d]{1,2}\/[\d]{2,4})\s*(?:at|by)/i);
    if (deadlineMatch && deadlineMatch[1]) {
      deadline = deadlineMatch[1].trim();
    }

    // Extract funding amounts
    let awardFloor = 0;
    let awardCeiling = 0;
    const amountMatches = html.match(/\$([\d,]+(?:\.\d{2})?)/g) || [];
    const amounts = amountMatches.map(a => parseInt(a.replace(/[$,]/g, ''))).filter(a => !isNaN(a) && a > 0 && a < 1000000000);
    if (amounts.length > 0) {
      awardFloor = Math.min(...amounts);
      awardCeiling = Math.max(...amounts);
    }

    // Extract eligibility
    let eligibility = '';
    const eligMatch = html.match(/[Ee]ligib[a-z]*[^<]*<\/(?:h[2-4]|dt|th|strong|b)>\s*(?:<[^>]+>)*\s*([\s\S]*?)(?=<\/div>|<h[2-4]|<dt)/i);
    if (eligMatch) {
      eligibility = eligMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500);
    }

    // Extract category
    const catMatch = html.match(/[Cc]ategor[a-z]*[^<]*<\/(?:dt|th|strong|b|span)>\s*(?:<[^>]+>)*\s*([^<]+)/i);
    const category = catMatch ? catMatch[1].trim() : 'State - California';

    // Generate stable oppNum from URL slug
    const slug = url.replace('https://www.grants.ca.gov/grants/', '').replace(/\/$/, '');
    const oppNum = 'CA-' + slug;

    grants.push({
      json: {
        id: oppNum,
        oppNum: oppNum,
        title: title,
        description: description || ('California state grant. Visit ' + url + ' for full details.'),
        link: url,
        openDate: new Date().toISOString().split('T')[0],
        closeDate: deadline,
        agency: agency,
        agencyCode: '',
        category: category,
        source: 'CA Grants Portal',
        awardFloor: awardFloor,
        awardCeiling: awardCeiling,
        status: 'posted',
        metadata: {
          eligibility: eligibility || null,
          sourceLevel: 'state',
          state: 'California'
        }
      }
    });
  } catch(e) {
    // Skip failed pages
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'ca-grants' } }];

// Extract grants from Grants.gov search2 API response
const items = $input.all();
const grants = [];

for (const item of items) {
  const response = item.json;

  let oppHits = [];
  if (response.data && response.data.oppHits) {
    oppHits = response.data.oppHits;
  } else if (response.oppHits) {
    oppHits = response.oppHits;
  } else if (Array.isArray(response)) {
    oppHits = response;
  }

  for (const opp of oppHits) {
    if (!opp || !opp.title) continue;

    const oppNum = opp.number || opp.opportunityNumber || 'GG-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
    const oppId = opp.id || opp.opportunityId;

    let description = '';
    let awardCeiling = parseInt(opp.awardCeiling) || 0;
    let awardFloor = parseInt(opp.awardFloor) || 0;
    let eligibility = '';
    let additionalEligibility = '';
    let estimatedFunding = '';
    let costSharing = '';
    let categoryOfFunding = '';
    let closeDate = opp.closeDate || 'See listing';
    let postedDate = opp.openDate || opp.postedDate || '';
    let cfdaNumbers = opp.cfdaList || [];
    let numberOfAwards = '';
    let fundingInstruments = '';
    let contactInfo = '';
    let archiveDate = '';
    let responseDateDesc = '';
    let fundingDescLink = '';

    // Fetch full details from Grants.gov REST API
    if (oppId) {
      try {
        const detail = await this.helpers.httpRequest({
          method: 'POST',
          url: 'https://apply07.grants.gov/grantsws/rest/opportunity/details',
          headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
          body: 'oppId=' + oppId,
        });

        // --- Synopsis section (posted grants) ---
        if (detail && detail.synopsis) {
          const syn = detail.synopsis;
          description = (syn.synopsisDesc || '').replace(/<[^>]+>/g, '').trim();
          const ceil = parseInt(syn.awardCeiling);
          const floor = parseInt(syn.awardFloor);
          if (!isNaN(ceil)) awardCeiling = ceil;
          if (!isNaN(floor)) awardFloor = floor;
          estimatedFunding = syn.estimatedFunding || '';
          costSharing = syn.costSharing ? 'Yes' : 'No';
          numberOfAwards = syn.numberOfAwards || '';
          if (syn.responseDate) closeDate = syn.responseDate;
          responseDateDesc = syn.responseDateDesc || '';
          if (syn.postingDate) postedDate = syn.postingDate;
          archiveDate = syn.archiveDate || '';
          fundingDescLink = syn.fundingDescLinkUrl || '';
          if (syn.agencyContactDesc) contactInfo = syn.agencyContactDesc;
          if (syn.agencyContactEmail) contactInfo += ' | ' + syn.agencyContactEmail;
          if (syn.applicantTypes && syn.applicantTypes.length > 0) {
            eligibility = syn.applicantTypes.map(t => t.description).join('; ');
          }
          additionalEligibility = syn.applicantEligibilityDesc || '';
          if (syn.fundingActivityCategories && syn.fundingActivityCategories.length > 0) {
            categoryOfFunding = syn.fundingActivityCategories.map(c => c.description).join('; ');
          }
          if (syn.fundingInstruments && syn.fundingInstruments.length > 0) {
            fundingInstruments = syn.fundingInstruments.map(f => f.description).join('; ');
          }
        }

        // --- Forecast section (forecasted grants) ---
        if (detail && detail.forecast) {
          const fc = detail.forecast;
          if (!description) {
            description = (fc.forecastDesc || fc.description || '').replace(/<[^>]+>/g, '').trim();
          }
          if (!estimatedFunding && fc.estimatedFunding) estimatedFunding = fc.estimatedFunding;
          if (!costSharing && fc.costSharing != null) costSharing = fc.costSharing ? 'Yes' : 'No';
          if (!numberOfAwards && fc.numberOfAwards) numberOfAwards = fc.numberOfAwards;
          if (closeDate === 'See listing' && fc.estimatedApplicationDueDate) closeDate = fc.estimatedApplicationDueDate;
          if (!postedDate && fc.estimatedPostDate) postedDate = fc.estimatedPostDate;
          if (!archiveDate && fc.archiveDate) archiveDate = fc.archiveDate;
          if (!fundingDescLink && fc.fundingDescLinkUrl) fundingDescLink = fc.fundingDescLinkUrl;
          if (!contactInfo && fc.agencyContactDesc) {
            contactInfo = fc.agencyContactDesc;
            if (fc.agencyContactEmail) contactInfo += ' | ' + fc.agencyContactEmail;
          }
          if (!eligibility && fc.applicantTypes && fc.applicantTypes.length > 0) {
